let accessToken;

function auth() {
  const url = `${authUrl}?client_id=${clientId}&redirect_uri=${redirectUri}&response_type=${responseType}&scope=${scope}`;
  window.location.href = url;
}

async function exchangeCode(code) {
  try {
    const response = await fetch(tokenUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: `client_id=${clientId}&client_secret=YOUR_CLIENT_SECRET&code=${code}&redirect_uri=${redirectUri}&grant_type=authorization_code`,
    });
    const data = await response.json();
    accessToken = data.access_token;
    localStorage.setItem('accessToken', accessToken);
  } catch (error) {
    console.error(error);
  }
}

function checkAuth() {
  const params = new URLSearchParams(window.location.search);
  if (params.get('code')) {
    exchangeCode(params.get('code'));
  } else if (accessToken) {
    // Use access token for API requests here
  } else {
    auth();
  }
}

